#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding endometriosis-assessment (15 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    preferred_name:string! \
    gender_identity:string! \
    ethnicity:string! \
    preferred_language:string! \
    interpreter_required:string! \
    gp_name:string! \
    gp_practice:string! \
    referrer_name:string! \
    referrer_role:string! \
    --htmx

cargo loco generate scaffold assessment_menstrual_history \
    assessment:references \
    age_at_menarche:int \
    cycle_regularity:string! \
    cycle_length_days:int \
    period_duration_days:int \
    flow_heaviness:string! \
    clots_present:string! \
    intermenstrual_bleeding:string! \
    postcoital_bleeding:string! \
    dysmenorrhoea_severity:string! \
    days_off_work_per_cycle:int \
    current_contraception:string! \
    menstrual_notes:text! \
    --htmx

cargo loco generate scaffold assessment_pain_assessment \
    assessment:references \
    has_pelvic_pain:string! \
    pelvic_pain_severity:int \
    pelvic_pain_character:string! \
    pelvic_pain_location:string! \
    pelvic_pain_timing:string! \
    dyspareunia:string! \
    dyspareunia_severity:int \
    dyschezia:string! \
    dyschezia_cyclical:string! \
    back_pain:string! \
    leg_pain:string! \
    pain_worse_with_activity:string! \
    pain_notes:text! \
    --htmx

cargo loco generate scaffold assessment_gastrointestinal_symptoms \
    assessment:references \
    has_gi_symptoms:string! \
    bloating:string! \
    bloating_cyclical:string! \
    nausea:string! \
    constipation:string! \
    diarrhoea:string! \
    alternating_bowel_habit:string! \
    rectal_bleeding:string! \
    rectal_bleeding_cyclical:string! \
    bowel_obstruction_symptoms:string! \
    gi_notes:text! \
    --htmx

cargo loco generate scaffold assessment_urinary_symptoms \
    assessment:references \
    has_urinary_symptoms:string! \
    frequency:string! \
    urgency:string! \
    dysuria:string! \
    haematuria:string! \
    haematuria_cyclical:string! \
    flank_pain:string! \
    urinary_obstruction_symptoms:string! \
    recurrent_utis:string! \
    urinary_notes:text! \
    --htmx

cargo loco generate scaffold assessment_fertility \
    assessment:references \
    trying_to_conceive:string! \
    duration_trying_months:int \
    previous_pregnancies:int \
    live_births:int \
    miscarriages:int \
    ectopic_pregnancies:int \
    previous_fertility_treatment:string! \
    fertility_treatment_details:text! \
    amh_level:double \
    partner_semen_analysis:string! \
    future_fertility_concerns:string! \
    fertility_notes:text! \
    --htmx

cargo loco generate scaffold assessment_previous_treatments \
    assessment:references \
    nsaids_tried:string! \
    nsaids_effective:string! \
    paracetamol_tried:string! \
    opioids_tried:string! \
    opioids_current:string! \
    combined_pill_tried:string! \
    combined_pill_effective:string! \
    progesterone_tried:string! \
    progesterone_type:string! \
    gnrh_agonist_tried:string! \
    gnrh_agonist_duration_months:int \
    mirena_ius_tried:string! \
    other_treatments:text! \
    treatment_notes:text! \
    --htmx

cargo loco generate scaffold assessment_surgical_history \
    assessment:references \
    previous_laparoscopy:string! \
    number_of_laparoscopies:int \
    most_recent_laparoscopy_date:date \
    endometriosis_confirmed_surgically:string! \
    histological_confirmation:string! \
    asrm_stage_at_surgery:string! \
    sites_found:text! \
    excision_performed:string! \
    ablation_performed:string! \
    adhesiolysis_performed:string! \
    endometrioma_drained:string! \
    bowel_surgery:string! \
    bladder_surgery:string! \
    other_pelvic_surgery:text! \
    surgical_complications:text! \
    surgical_notes:text! \
    --htmx

cargo loco generate scaffold assessment_quality_of_life \
    assessment:references \
    pain_domain_score:int \
    control_powerlessness_score:int \
    emotional_wellbeing_score:int \
    social_support_score:int \
    self_image_score:int \
    work_impact:string! \
    relationship_impact:string! \
    sleep_impact:string! \
    mental_health_impact:string! \
    exercise_impact:string! \
    qol_notes:text! \
    --htmx

cargo loco generate scaffold assessment_treatment_planning \
    assessment:references \
    treatment_goals:text! \
    preferred_approach:string! \
    surgery_considered:string! \
    surgery_type_considered:string! \
    fertility_preservation_needed:string! \
    mdt_referral_needed:string! \
    pain_management_referral:string! \
    psychology_referral:string! \
    physiotherapy_referral:string! \
    fertility_clinic_referral:string! \
    imaging_requested:string! \
    follow_up_interval:string! \
    planning_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    asrm_stage:string! \
    asrm_points:int \
    ehp30_total_score:int \
    overall_severity:string! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
